+        }
+        case 'dot': {
+          // Dot product
+          let dot = 0;
+          for (let i = 0; i < emb1.embedding.length; i++) {
+            dot += emb1.embedding[i] * emb2.embedding[i];
+          }
+          similarity = dot;
+          break;
+        }
+        case 'cosine':
+        default: {
+          // Cosine similarity
+          similarity = cosineSimilarity(emb1.embedding, emb2.embedding);
